function toFloat(high, low) {
    var buffer = new ArrayBuffer(4);
    var view = new DataView(buffer);
    view.setUint16(0, low);
    view.setUint16(2, high);
    var floatValue = view.getFloat32(0);
    return Math.round(floatValue * 100) / 100;
}
